import type { XYPosition } from '@xyflow/react';
import type { BpmnNode } from '@/src/types/bpmn/diagram';
import type { BpmnSymbolDefinition } from '@/src/types/bpmn/symbols';
import { getBpmnNodeSize, type BpmnNodeKind } from '@/src/components/bpmn/nodes/helpers';

function symbolToNodeKind(symbol: BpmnSymbolDefinition): BpmnNodeKind | null {
  if (symbol.reactFlowType === 'bpmnTask') return 'task';
  if (symbol.reactFlowType === 'bpmnSubprocess') return 'subprocess';
  if (symbol.reactFlowType === 'bpmnStartEvent') return 'event-start';
  if (symbol.reactFlowType === 'bpmnIntermediateEvent') return 'event-intermediate';
  if (symbol.reactFlowType === 'bpmnEndEvent') return 'event-end';
  if (symbol.reactFlowType === 'bpmnGateway') return 'gateway';
  if (symbol.reactFlowType === 'bpmnDataObject') return 'data-object';
  if (symbol.reactFlowType === 'bpmnDataStore') return 'data-store';
  if (symbol.reactFlowType === 'bpmnAnnotation') return 'annotation';
  if (symbol.reactFlowType === 'bpmnGroup') return 'group';
  if (symbol.reactFlowType === 'bpmnPool') return 'pool';
  if (symbol.reactFlowType === 'bpmnLane') return 'lane';
  return null;
}

export function createBpmnNode(symbol: BpmnSymbolDefinition, position: XYPosition): BpmnNode {
  const id = `${symbol.key}-${crypto.randomUUID()}`;
  const nodeKind = symbolToNodeKind(symbol);
  const size = nodeKind ? getBpmnNodeSize(nodeKind) : symbol.defaultSize;

  return {
    id,
    type: symbol.reactFlowType,
    position,
    data: {
      label: symbol.label,
      bpmnType: symbol.bpmnElement,
      bpmnCategory: symbol.category,
      ...symbol.defaultData,
      width: size.width,
      height: size.height,
      metadata: {
        bpmnXmlTag: symbol.bpmnXmlTag,
        symbolKey: symbol.key,
        ...symbol.defaultData,
      },
    },
    style: {
      width: size.width,
      height: size.height,
    },
  };
}
```

