## 5. `bpmn-symbol-store.ts` — Complete File

Zustand store (with `persist` middleware) managing the symbol panel state:

```ts
'use client';
import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { BPMN_SYMBOLS } from '@/src/lib/bpmn/symbols';
import type { BpmnFlowType } from '@/src/types/bpmn/symbols';

type BpmnSymbolState = {
  visibleSymbols: string[];
  searchQuery: string;
  selectedSymbol: string | null;
  connectionMode: boolean;
  activeFlowType: BpmnFlowType;
  isSymbolsPanelOpen: boolean;
  _hasHydrated: boolean;
  setHasHydrated: (value: boolean) => void;
  setSearchQuery: (query: string) => void;
  toggleSymbolVisibility: (key: string) => void;
  selectSymbol: (key: string | null) => void;
  activateConnectionMode: (flowType: BpmnFlowType) => void;
  closeSymbolsPanel: () => void;
  openSymbolsPanel: () => void;
  clearSearch: () => void;
};

const initialVisible = BPMN_SYMBOLS.map((s) => s.key);

export const useBpmnSymbolStore = create<BpmnSymbolState>()(
  persist(
    (set) => ({
      visibleSymbols: initialVisible,
      searchQuery: '',
      selectedSymbol: null,
      connectionMode: false,
      activeFlowType: 'sequence',
      isSymbolsPanelOpen: true,
      _hasHydrated: false,
      setHasHydrated: (value) => set({ _hasHydrated: value }),
      setSearchQuery: (searchQuery) => set({ searchQuery }),
      toggleSymbolVisibility: (key) =>
        set((state) => ({
          visibleSymbols: state.visibleSymbols.includes(key)
            ? state.visibleSymbols.filter((item) => item !== key)
            : [...state.visibleSymbols, key],
        })),
      selectSymbol: (selectedSymbol) => set({ selectedSymbol }),
      activateConnectionMode: (flowType) => set({ connectionMode: true, activeFlowType: flowType }),
      closeSymbolsPanel: () => set({ isSymbolsPanelOpen: false }),
      openSymbolsPanel: () => set({ isSymbolsPanelOpen: true }),
      clearSearch: () => set({ searchQuery: '' }),
    }),
    {
      name: 'bpmn-symbol-store',
      partialize: (state) => ({
        visibleSymbols: state.visibleSymbols,
        isSymbolsPanelOpen: state.isSymbolsPanelOpen,
      }),
      skipHydration: true,
      onRehydrateStorage: () => (state) => {
        state?.setHasHydrated(true);
      },
    }
  )
);
```

